  5→//! Gallops I/O operations with validation
  6→//!
  7→//! Provides validated load/save operations for Gallops JSON with round-trip guarantees.
  8→
  9→use std::fs;
 10→use std::path::Path;
 11→use crate::jjrt_types::jjrg_Gallops;
 12→use crate::jjrv_validate::jjrg_validate;
 13→
 14→/// Validated Gallops wrapper
 15→///
 16→/// This newtype ensures that Gallops instances are validated on load.
 17→/// Only jjdr_load can create instances, guaranteeing all ValidatedGallops
 18→/// have passed both deserialization and semantic validation.
 19→pub struct jjdr_ValidatedGallops(jjrg_Gallops);
 20→
 21→impl jjdr_ValidatedGallops {
 22→    /// Access the inner Gallops (immutable)
 23→    pub fn inner(&self) -> &jjrg_Gallops {
 24→        &self.0
 25→    }
 26→
 27→    /// Access the inner Gallops (mutable)
 28→    pub fn inner_mut(&mut self) -> &mut jjrg_Gallops {
 29→        &mut self.0
 30→    }
 31→
 32→    /// Consume the wrapper and return the inner Gallops
 33→    pub fn into_inner(self) -> jjrg_Gallops {
 34→        self.0
 35→    }
 36→
 37→    /// Test-only constructor (bypasses validation)
 38→    #[cfg(test)]
 39→    pub fn test_wrap(g: jjrg_Gallops) -> Self {
 40→        Self(g)
 41→    }
 42→}
 43→
 44→/// Find first byte position where two byte slices differ
 45→fn zjjdr_find_first_diff(a: &[u8], b: &[u8]) -> usize {
 46→    a.iter()
 47→        .zip(b.iter())
 48→        .position(|(x, y)| x != y)
 49→        .unwrap_or_else(|| a.len().min(b.len()))
 50→}
 51→
 52→/// Encode a firemark string into a case-safe paddock filename path.
 53→///
 54→/// Each character is prefixed with 'u' (uppercase) or 'l' (lowercase),
 55→/// ensuring the resulting filename is unambiguous on case-insensitive
 56→/// filesystems (macOS HFS+/APFS).
 57→///
 58→/// Examples:
 59→///   "AG" → ".claude/jjm/jjp_uAuG.md"
 60→///   "Ag" → ".claude/jjm/jjp_uAlg.md"
 61→///   "ag" → ".claude/jjm/jjp_lalg.md"
 62→pub fn jjri_paddock_path(firemark: &str) -> String {
 63→    let encoded: String = firemark.chars().map(|c| {
 64→        if c.is_uppercase() {
 65→            format!("u{}", c)
 66→        } else {
 67→            format!("l{}", c)
 68→        }
 69→    }).collect();
 70→    format!(".claude/jjm/jjp_{}.md", encoded)
 71→}
 72→
 73→/// Load and validate Gallops from a file
 74→///
 75→/// Performs these steps in order:
 76→/// 1. Deserialize JSON to Gallops struct
 77→/// 2. Round-trip validation: reserialize and compare bytes (validates stored format)
 78→/// 3. Recompute paddock_file from firemark for every heat (JJK owns this field)
 79→/// 4. Paddock existence check: fatal with mv instructions if files are at legacy paths
 80→/// 5. Semantic validation via jjrg_validate
 81→///
 82→/// Step 3 means the stored paddock_file value is ignored — JJK always derives it from
 83→/// the firemark. After migration, the next save writes the encoded value back to disk.
 84→///
 85→/// Returns ValidatedGallops wrapper that guarantees the data has passed all checks.
 86→pub fn jjdr_load(path: &Path) -> Result<jjdr_ValidatedGallops, String> {
 87→    // Read original bytes
 88→    let original_bytes = fs::read(path)
 89→        .map_err(|e| format!("Failed to read file '{}': {}", path.display(), e))?;
 90→
 91→    // Deserialize (mut: paddock_file will be recomputed below)
 92→    let mut gallops: jjrg_Gallops = serde_json::from_slice(&original_bytes)
 93→        .map_err(|e| format!("Failed to parse JSON: {}", e))?;
 94→
 95→    // Detect old-format files: heat_order absent or schema_version absent.
 96→    // Old-format files cannot pass round-trip check because BTreeMap serializes heats
 97→    // in sorted key order, which differs from original furlough-shuffled order.
 98→    //
 99→    // Also detect stale next_pensum_seed field (removed in v3.7 — pensum seeds moved
100→    // to officium-local storage). Serde silently ignores the unknown field on read,
101→    // but re-serialization omits it, causing round-trip byte mismatch until the next
102→    // save writes the clean format back to disk.
103→    const PENSUM_SEED_KEY: &[u8] = b"\"next_pensum_seed\"";
104→    let needs_pensum_seed_removal = !gallops.heats.is_empty()
105→        && original_bytes.windows(PENSUM_SEED_KEY.len()).any(|w| w == PENSUM_SEED_KEY);
106→    let is_migration_mode = gallops.heat_order.is_empty()
107→        || gallops.schema_version.is_none()
108→        || needs_pensum_seed_removal;
109→
110→    // Round-trip validation: run before recomputation to validate the stored format.
111→    // Skipped for old-format files (heat_order empty) — BTreeMap key order differs from
112→    // original IndexMap insertion order, so round-trip will always fail for these files.
113→    if !is_migration_mode {
114→        let reserialized = serde_json::to_string_pretty(&gallops)
115→            .map_err(|e| format!("Failed to reserialize JSON: {}", e))?;
116→
117→        if reserialized.as_bytes() != original_bytes {
118→            let diff_pos = zjjdr_find_first_diff(&original_bytes, reserialized.as_bytes());
119→            return Err(format!("Round-trip validation failed at byte {}", diff_pos));
120→        }
121→    }
122→
123→    // Recompute paddock_file from firemark for every heat.
124→    // JJK owns this field exclusively; whatever is stored in JSON is overwritten.
125→    // This allows old gallops files (with raw-firemark paths) to load transparently —
126→    // the correct encoded path is used in memory, and written back on the next save.
127→    for (firemark_key, heat) in &mut gallops.heats {
128→        let bare = firemark_key.trim_start_matches('₣');
129→        heat.paddock_file = jjri_paddock_path(bare);
130→    }
131→
132→    // Populate missing fields on first load of old-format file.
133→    // BTreeMap guarantees sorted key order for heat_order.
134→    if is_migration_mode {
135→        if gallops.heat_order.is_empty() {
136→            gallops.heat_order = gallops.heats.keys().cloned().collect();
137→        }
138→        gallops.schema_version = Some(4);
139→    }
140→
141→    // Paddock existence check: verify each encoded paddock file exists on disk.
142→    // If missing, compute the legacy raw-firemark path and emit mv instructions.
143→    // Reports ALL missing files at once so a single repair pass suffices.
144→    {
145→        let mut repairs: Vec<String> = Vec::new();
146→        for (firemark_key, heat) in &gallops.heats {
147→            if !Path::new(&heat.paddock_file).exists() {
148→                let bare = firemark_key.trim_start_matches('₣');
149→                let legacy_path = format!(".claude/jjm/jjp_{}.md", bare);
150→                if Path::new(&legacy_path).exists() {
151→                    repairs.push(format!("  mv {} {}", legacy_path, heat.paddock_file));
152→                } else {
153→                    repairs.push(format!(
154→                        "  # WARNING: paddock missing for heat \"{}\", expected: {}",
155→                        bare, heat.paddock_file
156→                    ));
157→                }
158→            }
159→        }
160→        if !repairs.is_empty() {
161→            return Err(format!(
162→                "Paddock files need renaming before proceeding:\n\n{}",
163→                repairs.join("\n")
164→            ));
165→        }
166→    }
167→
168→    // Semantic validation
169→    jjrg_validate(&gallops)
170→        .map_err(|errors| format!("Validation failed: {}", errors.join("; ")))?;
171→
172→    Ok(jjdr_ValidatedGallops(gallops))
173→}
174→
175→/// Save Gallops to a file with validation
176→///
177→/// Performs atomic write with validation:
178→/// 1. Serialize to JSON
179→/// 2. Write to temp file
180→/// 3. Validate temp file via jjdr_load
181→/// 4. Rename temp to target (atomic)
182→///
183→/// If validation fails, temp file is deleted and error returned.
184→pub fn jjdr_save(gallops: &jjrg_Gallops, path: &Path) -> Result<(), String> {
185→    // Serialize to pretty JSON
186→    let json = serde_json::to_string_pretty(gallops)
187→        .map_err(|e| format!("Failed to serialize JSON: {}", e))?;
188→
189→    // Create temp file in same directory for atomic rename
190→    let parent = path.parent().ok_or_else(|| "Invalid path: no parent directory".to_string())?;
191→    let temp_path = parent.join(format!(".tmp.{}.json", std::process::id()));
192→
193→    // Write to temp file
194→    fs::write(&temp_path, &json)
195→        .map_err(|e| format!("Failed to write temp file: {}", e))?;
196→
197→    // Validate what we wrote by loading it back
198→    match jjdr_load(&temp_path) {
199→        Ok(_) => {
200→            // Validation passed, rename to target
201→            fs::rename(&temp_path, path)
202→                .map_err(|e| format!("Failed to rename temp file to target: {}", e))?;
203→            Ok(())
204→        }
205→        Err(e) => {
206→            // Validation failed, clean up temp file
207→            let _ = fs::remove_file(&temp_path);
208→            Err(format!("Save validation failed: {}", e))
209→        }
210→    }
211→}
212→
213→/// Save Gallops and commit with paddock in a single operation
214→///
215→/// This is the standard routine for JJK operations that modify gallops.
216→/// It saves the gallops file, then commits both the gallops and the paddock file
217→/// for the given heat using machine_commit.
218→///
219→/// Returns the commit hash on success.
220→pub fn jjri_persist(
221→    lock: &vvc::vvcc_CommitLock,
222→    gallops: &jjrg_Gallops,
223→    file: &Path,
224→    firemark: &crate::jjrf_favor::jjrf_Firemark,
225→    message: String,
226→    size_limit: u64,
227→    output: &mut vvc::vvco_Output,
228→) -> Result<String, String> {
229→    // Save gallops first
230→    jjdr_save(gallops, file)?;
231→
232→    // Construct paths for commit
233→    let gallops_path = file.to_string_lossy().to_string();
234→    let paddock_path = jjri_paddock_path(firemark.jjrf_as_str());
235→
236→    // Commit using machine_commit with explicit file list
237→    let commit_args = vvc::vvcm_CommitArgs {
238→        files: vec![
239→            gallops_path,
240→            paddock_path,
241→        ],
242→        message,
243→        size_limit,
244→        warn_limit: 30000,
245→    };
246→
247→    vvc::machine_commit(lock, &commit_args, output)
248→}
