  5→//! Gallops validation routines
  6→//!
  7→//! Validates Gallops JSON structure against schema rules.
  8→
  9→use std::collections::HashSet;
 10→use crate::jjrf_favor::JJRF_CHARSET;
 11→use crate::jjrt_types::*;
 12→
 13→/// Check if string contains only URL-safe base64 characters
 14→#[allow(dead_code)]
 15→pub(crate) fn zjjrg_is_base64(s: &str) -> bool {
 16→    s.bytes().all(|b| JJRF_CHARSET.contains(&b))
 17→}
 18→
 19→/// Check if string is valid kebab-case (non-empty, alphanumeric with hyphens, case-insensitive)
 20→#[allow(dead_code)]
 21→pub(crate) fn zjjrg_is_kebab_case(s: &str) -> bool {
 22→    if s.is_empty() {
 23→        return false;
 24→    }
 25→    // Pattern: [a-zA-Z0-9]+(-[a-zA-Z0-9]+)*
 26→    let parts: Vec<&str> = s.split('-').collect();
 27→    for part in parts {
 28→        if part.is_empty() {
 29→            return false;
 30→        }
 31→        if !part.chars().all(|c| c.is_ascii_alphanumeric()) {
 32→            return false;
 33→        }
 34→    }
 35→    true
 36→}
 37→
 38→/// Check if string matches YYMMDD format
 39→#[allow(dead_code)]
 40→pub(crate) fn zjjrg_is_yymmdd(s: &str) -> bool {
 41→    if s.len() != 6 {
 42→        return false;
 43→    }
 44→    s.chars().all(|c| c.is_ascii_digit())
 45→}
 46→
 47→/// Check if string matches YYMMDD-HHMM format
 48→#[allow(dead_code)]
 49→pub(crate) fn zjjrg_is_yymmdd_hhmm(s: &str) -> bool {
 50→    if s.len() != 11 {
 51→        return false;
 52→    }
 53→    let parts: Vec<&str> = s.split('-').collect();
 54→    if parts.len() != 2 {
 55→        return false;
 56→    }
 57→    parts[0].len() == 6
 58→        && parts[0].chars().all(|c| c.is_ascii_digit())
 59→        && parts[1].len() == 4
 60→        && parts[1].chars().all(|c| c.is_ascii_digit())
 61→}
 62→
 63→/// Check if string is valid commit SHA format (used for basis field)
 64→///
 65→/// Length is derived from JJRG_UNKNOWN_BASIS constant.
 66→#[allow(dead_code)]
 67→pub(crate) fn zjjrg_is_commit_sha(s: &str) -> bool {
 68→    s.len() == JJRG_UNKNOWN_BASIS.len() && s.chars().all(|c| c.is_ascii_hexdigit())
 69→}
 70→
 71→/// Validate the Gallops structure
 72→///
 73→/// Returns Ok(()) if valid, Err(Vec<String>) with all validation errors otherwise.
 74→pub fn jjrg_validate(gallops: &jjrg_Gallops) -> Result<(), Vec<String>> {
 75→    let mut errors = Vec::new();
 76→
 77→    // Rule 0: schema_version must be Some(4)
 78→    match gallops.schema_version {
 79→        Some(4) => {}
 80→        Some(v) => {
 81→            errors.push(format!("schema_version must be 4, got {}", v));
 82→        }
 83→        None => {
 84→            errors.push("schema_version is missing".to_string());
 85→        }
 86→    }
 87→
 88→    // Rule 1: next_heat_seed must be 2 URL-safe base64 characters
 89→    if gallops.next_heat_seed.len() != 2 {
 90→        errors.push(format!(
 91→            "next_heat_seed must be 2 characters, got {}",
 92→            gallops.next_heat_seed.len()
 93→        ));
 94→    } else if !zjjrg_is_base64(&gallops.next_heat_seed) {
 95→        errors.push(format!(
 96→            "next_heat_seed contains invalid base64 characters: '{}'",
 97→            gallops.next_heat_seed
 98→        ));
 99→    }
100→
101→    // Rule 2: heats object exists (implicitly satisfied by struct)
102→
103→    // Validate each Heat
104→    for (heat_key, heat) in &gallops.heats {
105→        zjjrg_validate_heat(heat_key, heat, &mut errors);
106→    }
107→
108→    if errors.is_empty() {
109→        Ok(())
110→    } else {
111→        Err(errors)
112→    }
113→}
114→
115→fn zjjrg_validate_heat(heat_key: &str, heat: &jjrg_Heat, errors: &mut Vec<String>) {
116→    let heat_ctx = format!("Heat '{}'", heat_key);
117→
118→    // Rule 3: Heat key must match ₣[A-Za-z0-9_-]{2}
119→    if !heat_key.starts_with('₣') {
120→        errors.push(format!("{}: key must start with '₣'", heat_ctx));
121→    } else {
122→        let suffix = &heat_key[3..]; // ₣ is 3 bytes in UTF-8
123→        if suffix.len() != 2 {
124→            errors.push(format!(
125→                "{}: key must have 2 base64 chars after '₣', got {}",
126→                heat_ctx,
127→                suffix.len()
128→            ));
129→        } else if !zjjrg_is_base64(suffix) {
130→            errors.push(format!(
131→                "{}: key contains invalid base64 characters",
132→                heat_ctx
133→            ));
134→        }
135→    }
136→
137→    // Rule 4: Required Heat fields
138→    // silks (non-empty alphanumeric-kebab)
139→    if !zjjrg_is_kebab_case(&heat.silks) {
140→        errors.push(format!(
141→            "{}: silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'",
142→            heat_ctx, heat.silks
143→        ));
144→    }
145→
146→    // creation_time (YYMMDD)
147→    if !zjjrg_is_yymmdd(&heat.creation_time) {
148→        errors.push(format!(
149→            "{}: creation_time must be YYMMDD format, got '{}'",
150→            heat_ctx, heat.creation_time
151→        ));
152→    }
153→
154→    // status (validated by serde enum)
155→
156→    // next_pace_seed (3 URL-safe base64 characters)
157→    if heat.next_pace_seed.len() != 3 {
158→        errors.push(format!(
159→            "{}: next_pace_seed must be 3 characters, got {}",
160→            heat_ctx,
161→            heat.next_pace_seed.len()
162→        ));
163→    } else if !zjjrg_is_base64(&heat.next_pace_seed) {
164→        errors.push(format!(
165→            "{}: next_pace_seed contains invalid base64 characters",
166→            heat_ctx
167→        ));
168→    }
169→
170→    // Extract heat identity (base64 part without prefix) for pace validation
171→    let heat_identity = if heat_key.starts_with('₣') && heat_key.len() >= 5 {
172→        Some(&heat_key[3..]) // ₣ is 3 bytes
173→    } else {
174→        None
175→    };
176→
177→    // Rule 5: order array and paces object must have identical key sets
178→    let order_set: HashSet<&String> = heat.order.iter().collect();
179→    let _paces_set: HashSet<&String> = heat.paces.keys().collect();
180→
181→    if order_set.len() != heat.order.len() {
182→        errors.push(format!("{}: order array contains duplicate entries", heat_ctx));
183→    }
184→
185→    let in_order_not_paces: Vec<_> = heat
186→        .order
187→        .iter()
188→        .filter(|k| !heat.paces.contains_key(*k))
189→        .collect();
190→    let in_paces_not_order: Vec<_> = heat
191→        .paces
192→        .keys()
193→        .filter(|k| !order_set.contains(k))
194→        .collect();
195→
196→    if !in_order_not_paces.is_empty() {
197→        errors.push(format!(
198→            "{}: order contains keys not in paces: {:?}",
199→            heat_ctx, in_order_not_paces
200→        ));
201→    }
202→    if !in_paces_not_order.is_empty() {
203→        errors.push(format!(
204→            "{}: paces contains keys not in order: {:?}",
205→            heat_ctx, in_paces_not_order
206→        ));
207→    }
208→
209→    // Validate each Pace
210→    for (pace_key, pace) in &heat.paces {
211→        zjjrg_validate_pace(&heat_ctx, heat_identity, pace_key, pace, errors);
212→    }
213→}
214→
215→fn zjjrg_validate_pace(
216→    heat_ctx: &str,
217→    heat_identity: Option<&str>,
218→    pace_key: &str,
219→    pace: &jjrg_Pace,
220→    errors: &mut Vec<String>,
221→) {
222→    let pace_ctx = format!("{} Pace '{}'", heat_ctx, pace_key);
223→
224→    // Rule 6: Pace key must match ₢[A-Za-z0-9_-]{5}
225→    if !pace_key.starts_with('₢') {
226→        errors.push(format!("{}: key must start with '₢'", pace_ctx));
227→    } else {
228→        let suffix = &pace_key[3..]; // ₢ is 3 bytes in UTF-8
229→        if suffix.len() != 5 {
230→            errors.push(format!(
231→                "{}: key must have 5 base64 chars after '₢', got {}",
232→                pace_ctx,
233→                suffix.len()
234→            ));
235→        } else {
236→            if !zjjrg_is_base64(suffix) {
237→                errors.push(format!(
238→                    "{}: key contains invalid base64 characters",
239→                    pace_ctx
240→                ));
241→            }
242→            // Pace must embed parent Heat identity (first 2 chars)
243→            if let Some(heat_id) = heat_identity {
244→                if !suffix.starts_with(heat_id) {
245→                    errors.push(format!(
246→                        "{}: key must embed parent heat identity '{}', got '{}'",
247→                        pace_ctx,
248→                        heat_id,
249→                        &suffix[..2.min(suffix.len())]
250→                    ));
251→                }
252→            }
253→        }
254→    }
255→
256→    // Rule 7: tacks must be non-empty array
257→    if pace.tacks.is_empty() {
258→        errors.push(format!("{}: tacks array must not be empty", pace_ctx));
259→    }
260→
261→    // Validate each Tack
262→    for (i, tack) in pace.tacks.iter().enumerate() {
263→        zjjrg_validate_tack(&pace_ctx, i, tack, errors);
264→    }
265→}
266→
267→fn zjjrg_validate_tack(pace_ctx: &str, index: usize, tack: &jjrg_Tack, errors: &mut Vec<String>) {
268→    let tack_ctx = format!("{} Tack[{}]", pace_ctx, index);
269→
270→    // Rule 8: ts must be YYMMDD-HHMM
271→    if !zjjrg_is_yymmdd_hhmm(&tack.ts) {
272→        errors.push(format!(
273→            "{}: ts must be YYMMDD-HHMM format, got '{}'",
274→            tack_ctx, tack.ts
275→        ));
276→    }
277→
278→    // Rule 8: text must be non-empty
279→    if tack.text.is_empty() {
280→        errors.push(format!("{}: text must not be empty", tack_ctx));
281→    }
282→
283→    // Rule 8: silks must be non-empty alphanumeric-kebab
284→    if !zjjrg_is_kebab_case(&tack.silks) {
285→        errors.push(format!(
286→            "{}: silks must be non-empty alphanumeric-kebab (letters, digits, hyphens), got '{}'",
287→            tack_ctx, tack.silks
288→        ));
289→    }
290→
291→    // Rule 8: basis must be valid format (7 hex chars)
292→    if !zjjrg_is_commit_sha(&tack.basis) {
293→        errors.push(format!(
294→            "{}: basis must be 7 hex characters, got '{}'",
295→            tack_ctx, tack.basis
296→        ));
297→    }
298→
299→    // Rule 9: direction presence depends on state
300→    match tack.state {
301→        jjrg_PaceState::Bridled => {
302→            match &tack.direction {
303→                None => {
304→                    errors.push(format!(
305→                        "{}: direction is required when state is 'bridled'",
306→                        tack_ctx
307→                    ));
308→                }
309→                Some(d) if d.is_empty() => {
310→                    errors.push(format!(
311→                        "{}: direction must not be empty when state is 'bridled'",
312→                        tack_ctx
313→                    ));
314→                }
315→                _ => {}
316→            }
317→        }
318→        _ => {
319→            if tack.direction.is_some() {
320→                errors.push(format!(
321→                    "{}: direction must be absent when state is not 'bridled'",
322→                    tack_ctx
323→                ));
324→            }
325→        }
326→    }
327→}
