515→// ============================================================================
516→// jjx_fetch — read single file from fundus
517→// ============================================================================
518→
519→pub struct jjrlg_FetchArgs {
520→    pub legatio: String,
521→    pub path: String,
522→}
523→
524→/// Read a single file from the fundus via SSH.
525→///
526→/// Path is relative to RELDIR if it doesn't start with `/`,
527→/// or absolute if it does. Returns file content as text (lossy UTF-8).
528→pub fn jjrlg_run_fetch(args: jjrlg_FetchArgs, officium_id: &str) -> (i32, String) {
529→    let cn = JJRLG_CMD_NAME_FETCH;
530→    let mut output = vvco_Output::buffer();
531→
532→    let officium_dir = zjjrlg_officium_dir(officium_id);
533→    let state = match zjjrlg_load_legatio(&officium_dir, &args.legatio) {
534→        Ok(s) => s,
535→        Err(e) => {
536→            vvco_err!(output, "{}: {}", cn, e);
537→            return (1, output.vvco_finish());
538→        }
539→    };
540→
541→    // Absolute paths pass through; relative paths resolve against RELDIR
542→    let cat_cmd = if args.path.starts_with('/') {
543→        format!("cat {}", zjjrlg_shell_quote(&args.path))
544→    } else {
545→        format!(
546→            "cd \"$HOME/{}\" && cat {}",
547→            state.reldir,
548→            zjjrlg_shell_quote(&args.path)
549→        )
550→    };
551→
552→    let result = match zjjrlg_ssh_exec(&state.host, &state.user, &cat_cmd) {
553→        Ok(r) => r,
554→        Err(e) => {
555→            vvco_err!(output, "{}: SSH failed: {}", cn, e);
556→            return (1, output.vvco_finish());
557→        }
558→    };
559→
560→    if result.exit_code != 0 {
561→        let stderr = String::from_utf8_lossy(&result.stderr);
562→        vvco_err!(output, "{}: failed (exit {}): {}", cn, result.exit_code, stderr.trim());
563→        return (1, output.vvco_finish());
564→    }
565→
566→    let content = String::from_utf8_lossy(&result.stdout);
567→    vvco_out!(output, "{}", content);
568→
569→    (0, output.vvco_finish())
570→}
