572→// ============================================================================
573→// BURX parsing
574→// ============================================================================
575→
576→/// Parse burx.env content as key=value pairs.
577→fn zjjrlg_parse_burx(content: &str) -> HashMap<String, String> {
578→    let mut map = HashMap::new();
579→    for line in content.lines() {
580→        if let Some((key, value)) = line.split_once('=') {
581→            map.insert(key.to_string(), value.to_string());
582→        }
583→    }
584→    map
585→}
