630→// ============================================================================
631→// Pensum minting (officium-local storage)
632→// ============================================================================
633→
634→/// Mint a pensum token via officium-local seed storage.
635→///
636→/// Reads/writes pensum_seeds.json in the officium directory (keyed by firemark).
637→/// No gallops lock, no git commit — pensum tokens are ephemeral correlation labels.
638→fn zjjrlg_mint_pensum_local(
639→    firemark_input: &str,
640→    officium_dir: &Path,
641→) -> Result<crate::jjrf_favor::jjrf_Pensum, String> {
642→    use crate::jjrf_favor::{jjrf_Firemark, jjrf_Pensum, JJRF_PENSUM_SENTINEL};
643→    use crate::jjru_util::zjjrg_increment_seed;
644→
645→    let firemark = jjrf_Firemark::jjrf_parse(firemark_input)
646→        .map_err(|e| format!("Invalid firemark: {}", e))?;
647→    let firemark_key = firemark.jjrf_display();
648→
649→    let seeds_path = officium_dir.join(PENSUM_SEEDS_FILE);
650→
651→    // Load existing seeds or start empty
652→    let mut seeds: HashMap<String, String> = if seeds_path.exists() {
653→        let content = std::fs::read_to_string(&seeds_path)
654→            .map_err(|e| format!("Cannot read pensum seeds: {}", e))?;
655→        serde_json::from_str(&content)
656→            .map_err(|e| format!("Cannot parse pensum seeds: {}", e))?
657→    } else {
658→        HashMap::new()
659→    };
660→
661→    // Get or initialize seed for this heat
662→    let seed = seeds.entry(firemark_key.clone())
663→        .or_insert_with(|| crate::jjrt_types::JJRT_PENSUM_SEED_INIT.to_string());
664→
665→    let pensum = jjrf_Pensum(format!("{}{}{}",
666→        firemark.jjrf_as_str(),
667→        JJRF_PENSUM_SENTINEL,
668→        seed,
669→    ));
670→
671→    // Increment seed
672→    *seed = zjjrg_increment_seed(seed);
673→
674→    // Persist seeds back
675→    let json = serde_json::to_string_pretty(&seeds)
676→        .map_err(|e| format!("Cannot serialize pensum seeds: {}", e))?;
677→    std::fs::write(&seeds_path, json.as_bytes())
678→        .map_err(|e| format!("Cannot write pensum seeds: {}", e))?;
679→
680→    Ok(pensum)
681→}
