694→/// Verify curia git state is clean and pushed before remote dispatch.
695→/// Returns Ok(()) if ready, Err(message) if not.
696→fn zjjrlg_require_curia_ready() -> Result<(), String> {
697→    use crate::jjrt_types::JJRG_UNKNOWN_BASIS;
698→
699→    let z_abbrev_len = JJRG_UNKNOWN_BASIS.len();
700→

700→
701→    // Check working tree is clean
702→    let z_status = vvc::vvce_git_command(&["status", "--porcelain"])
703→        .output()
704→        .map_err(|e| format!("git status failed: {}", e))?;
705→    let z_status_text = String::from_utf8_lossy(&z_status.stdout);
706→    let z_dirty_count = z_status_text.lines().filter(|l| !l.is_empty()).count();
707→    if z_dirty_count > 0 {
708→        return Err(format!(
709→            "curia working tree is dirty ({} files). Commit before dispatching.", z_dirty_count
710→        ));
711→    }
712→
713→    // Check HEAD is pushed to origin
714→    let z_head = vvc::vvce_git_command(&["rev-parse", "HEAD"])
715→        .output()
716→        .map_err(|e| format!("git rev-parse HEAD failed: {}", e))?;
717→    let z_head_sha = String::from_utf8_lossy(&z_head.stdout).trim().to_string();
718→
719→    let z_branch = vvc::vvce_git_command(&["rev-parse", "--abbrev-ref", "HEAD"])
720→        .output()
721→        .map_err(|e| format!("git rev-parse --abbrev-ref failed: {}", e))?;
722→    let z_branch_name = String::from_utf8_lossy(&z_branch.stdout).trim().to_string();
723→
724→    let z_remote_ref = format!("origin/{}", z_branch_name);
725→    let z_remote = vvc::vvce_git_command(&["rev-parse", &z_remote_ref])
726→        .output()
727→        .map_err(|e| format!("git rev-parse {} failed: {}", z_remote_ref, e))?;
728→    let z_remote_sha = String::from_utf8_lossy(&z_remote.stdout).trim().to_string();
729→
730→    if z_head_sha != z_remote_sha {
731→        return Err(format!(
732→            "curia HEAD {} is not pushed to {} (remote {}). Push before dispatching.",
733→            &z_head_sha[..z_abbrev_len.min(z_head_sha.len())],
734→            z_remote_ref,
735→            &z_remote_sha[..z_abbrev_len.min(z_remote_sha.len())]
736→        ));
737→    }
738→
739→    Ok(())
740→}
